content.text:
A arquitetura pode ser organizada em um container principal `CRMLayout` com duas regiões: `Sidebar` fixa (estado `collapsed`) e `MainArea` com `Topbar`, `FilterBar` e `KanbanBoard`. O estado global da tela fica em `App` (cards, coluna de drag, modal da agenda, sidebar aberta/fechada), facilitando evolução para API/backend depois. Cada card carrega metadados de agenda (`agendaStatus`) para refletir alertas visuais diretamente no Kanban.

Para manter o código escalável, os componentes são separados por responsabilidade: `Sidebar`, `Topbar`, `FilterBar`, `KanbanBoard`, `KanbanColumn`, `KanbanCard` e `AgendaModal`. O drag-and-drop usa HTML5 DnD com classes de estado (`isDragging`, `isDropTarget`), e o modal já traz estrutura semântica pronta para futura sincronização bidirecional entre agenda e oportunidades.

```jsx
// App.jsx
import React, { useMemo, useState } from "react";
import "./App.css";

const initialColumns = [
  { id: "qualification", title: "Qualificação", subtitle: "142 oportunidades" },
  { id: "scheduled_meeting", title: "Reunião agendada", subtitle: "76 oportunidades" },
  { id: "proposal_sent", title: "Envio de Proposta", subtitle: "30 oportunidades" },
  { id: "contract_activation", title: "Contrato e ativação", subtitle: "21 oportunidades" },
];

const initialCards = [
  {
    id: "c1",
    columnId: "qualification",
    title: "Oportunidade",
    source: "🖥️ Marketing",
    owner: "AL",
    value: "R$ 57.145,00",
    tagColor: "green",
    daysInStage: "10d",
    agendaStatus: "today", // normal | today | overdue
  },
  {
    id: "c2",
    columnId: "qualification",
    title: "Oportunidade",
    source: "🤝 Indicação",
    owner: "MS",
    value: "R$ 22.400,00",
    tagColor: "purple",
    daysInStage: "15d",
    agendaStatus: "normal",
  },
  {
    id: "c3",
    columnId: "scheduled_meeting",
    title: "Oportunidade",
    source: "🖥️ Marketing",
    owner: "JP",
    value: "R$ 9.870,00",
    tagColor: "yellow",
    daysInStage: "8d",
    agendaStatus: "overdue",
  },
  {
    id: "c4",
    columnId: "proposal_sent",
    title: "Oportunidade",
    source: "🤝 Indicação",
    owner: "CR",
    value: "R$ 44.000,00",
    tagColor: "green",
    daysInStage: "12d",
    agendaStatus: "normal",
  },
];

const agendaItems = [
  { id: "a1", title: "Retorno - Empresa Atlas", date: "Hoje 10:30", status: "today" },
  { id: "a2", title: "Ligação - Lead Beta", date: "Hoje 15:00", status: "today" },
  { id: "a3", title: "Follow-up - Cliente Orion", date: "Ontem 16:00", status: "overdue" },
  { id: "a4", title: "Reunião - Proposta Delta", date: "Quarta 11:00", status: "upcoming" },
];

function App() {
  const [cards, setCards] = useState(initialCards);
  const [draggingCardId, setDraggingCardId] = useState(null);
  const [dropTargetColumnId, setDropTargetColumnId] = useState(null);
  const [isAgendaOpen, setIsAgendaOpen] = useState(false);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  const cardsByColumn = useMemo(() => {
    return initialColumns.reduce((acc, col) => {
      acc[col.id] = cards.filter((card) => card.columnId === col.id);
      return acc;
    }, {});
  }, [cards]);

  const handleDragStart = (cardId) => {
    setDraggingCardId(cardId);
  };

  const handleDragEnd = () => {
    setDraggingCardId(null);
    setDropTargetColumnId(null);
  };

  const handleDropOnColumn = (columnId) => {
    if (!draggingCardId) return;
    setCards((prev) =>
      prev.map((card) =>
        card.id === draggingCardId ? { ...card, columnId } : card
      )
    );
    setDraggingCardId(null);
    setDropTargetColumnId(null);
  };

  return (
    <div className="appShell">
      <Sidebar
        collapsed={isSidebarCollapsed}
        onToggle={() => setIsSidebarCollapsed((prev) => !prev)}
      />

      <main className="mainArea">
        <Topbar onOpenAgenda={() => setIsAgendaOpen(true)} />
        <FilterBar />
        <KanbanBoard
          columns={initialColumns}
          cardsByColumn={cardsByColumn}
          draggingCardId={draggingCardId}
          dropTargetColumnId={dropTargetColumnId}
          onDragStart={handleDragStart}
          onDragEnd={handleDragEnd}
          onDragEnterColumn={setDropTargetColumnId}
          onDropOnColumn={handleDropOnColumn}
        />
      </main>

      <AgendaModal
        isOpen={isAgendaOpen}
        onClose={() => setIsAgendaOpen(false)}
        items={agendaItems}
      />
    </div>
  );
}

function Sidebar({ collapsed, onToggle }) {
  const items = [
    { label: "Resumos", icon: "📊" },
    { label: "Clientes", icon: "👥" },
    { label: "Processos", icon: "🧩", active: true },
    { label: "Documentos", icon: "📁" },
    { label: "Produtos", icon: "📦" },
    { label: "Relatórios Beta", icon: "🧪", beta: true },
    { label: "Relatórios", icon: "📈" },
    { label: "Biblioteca", icon: "📚" },
  ];

  return (
    <aside className={`sidebar ${collapsed ? "collapsed" : ""}`}>
      <div className="sidebarHeader">
        <div className="logoPlaceholder">{collapsed ? "A" : "Antigravity CRM"}</div>
        <button className="collapseBtn" onClick={onToggle} aria-label="Recolher menu">
          {collapsed ? "➡" : "⬅"}
        </button>
      </div>

      <nav className="sidebarNav">
        {items.map((item) => (
          <button key={item.label} className={`navItem ${item.active ? "active" : ""}`}>
            <span className="navIcon">{item.icon}</span>
            {!collapsed && (
              <span className="navText">
                {item.label}
                {item.beta && <span className="betaTag">Beta</span>}
              </span>
            )}
          </button>
        ))}
      </nav>
    </aside>
  );
}

function Topbar({ onOpenAgenda }) {
  return (
    <header className="topbar">
      <button className="newBtn">+ Novo</button>

      <div className="topbarActions">
        <button className="iconBtn withBadge" aria-label="Notificações">
          🔔
          <span className="badge">6</span>
        </button>
        <button className="iconBtn" aria-label="Telefone">📞</button>
        <button className="iconBtn" aria-label="Suporte">🆘</button>
        <button className="iconBtn" aria-label="Agenda" onClick={onOpenAgenda}>📅</button>
        <div className="userAvatar">RS</div>
      </div>
    </header>
  );
}

function FilterBar() {
  return (
    <section className="filterBar">
      <select className="filterSelect">
        <option>Indústrias</option>
        <option>Tecnologia</option>
        <option>Saúde</option>
        <option>Financeiro</option>
      </select>

      <select className="filterSelect">
        <option>Minhas negociações</option>
        <option>Todas</option>
        <option>Equipe</option>
      </select>

      <select className="filterSelect">
        <option>Origem</option>
        <option>Marketing</option>
        <option>Indicação</option>
        <option>Outbound</option>
      </select>
    </section>
  );
}

function KanbanBoard({
  columns,
  cardsByColumn,
  draggingCardId,
  dropTargetColumnId,
  onDragStart,
  onDragEnd,
  onDragEnterColumn,
  onDropOnColumn,
}) {
  return (
    <section className="kanbanArea">
      <div className="kanbanGrid">
        {columns.map((column) => (
          <KanbanColumn
            key={column.id}
            column={column}
            cards={cardsByColumn[column.id] || []}
            draggingCardId={draggingCardId}
            isDropTarget={dropTargetColumnId === column.id}
            onDragEnterColumn={onDragEnterColumn}
            onDropOnColumn={onDropOnColumn}
            onDragStart={onDragStart}
            onDragEnd={onDragEnd}
          />
        ))}
      </div>
    </section>
  );
}

function KanbanColumn({
  column,
  cards,
  draggingCardId,
  isDropTarget,
  onDragEnterColumn,
  onDropOnColumn,
  onDragStart,
  onDragEnd,
}) {
  return (
    <article
      className={`kanbanColumn ${isDropTarget ? "isDropTarget" : ""}`}
      onDragOver={(e) => {
        e.preventDefault();
        onDragEnterColumn(column.id);
      }}
      onDragEnter={() => onDragEnterColumn(column.id)}
      onDrop={(e) => {
        e.preventDefault();
        onDropOnColumn(column.id);
      }}
    >
      <header className="columnHeader">
        <h3>{column.title}</h3>
        <p>{column.subtitle}</p>
      </header>

      <div className="columnCards">
        {cards.map((card) => (
          <KanbanCard
            key={card.id}
            card={card}
            isDragging={draggingCardId === card.id}
            onDragStart={onDragStart}
            onDragEnd={onDragEnd}
          />
        ))}
      </div>
    </article>
  );
}

function KanbanCard({ card, isDragging, onDragStart, onDragEnd }) {
  return (
    <div
      className={`kanbanCard ${isDragging ? "isDragging" : ""} ${
        card.agendaStatus === "today" || card.agendaStatus === "overdue" ? "hasAgendaAlert" : ""
      } ${card.agendaStatus === "overdue" ? "isOverdue" : ""}`}
      draggable
      onDragStart={() => onDragStart(card.id)}
      onDragEnd={onDragEnd}
    >
      <button className="editBtn" aria-label="Editar oportunidade">✏️</button>

      <p className="cardTitle">
        {card.title} <span>({card.source})</span>
      </p>

      <footer className="cardFooter">
        <div className="ownerAvatar">{card.owner}</div>

        <div className={`moneyTag ${card.tagColor}`}>
          <span>🏷️</span> {card.value}
        </div>

        <div className="stageTime">
          {card.agendaStatus === "today" && <span className="alertTime">⏰ Hoje</span>}
          {card.agendaStatus === "overdue" && <span className="alertTime overdue">⏰ Atrasado</span>}
          {card.agendaStatus === "normal" && <span>{card.daysInStage}</span>}
        </div>
      </footer>
    </div>
  );
}

function AgendaModal({ isOpen, onClose, items }) {
  if (!isOpen) return null;

  return (
    <div className="modalOverlay" role="dialog" aria-modal="true">
      <div className="agendaModal">
        <header className="agendaHeader">
          <h2>Agenda de compromissos</h2>
          <button className="closeBtn" onClick={onClose}>✕</button>
        </header>

        <section className="calendarView">
          <div className="calendarGrid">
            <div className="dayCell muted">28</div>
            <div className="dayCell muted">29</div>
            <div className="dayCell muted">30</div>
            <div className="dayCell">1</div>
            <div className="dayCell">2</div>
            <div className="dayCell today">3</div>
            <div className="dayCell">4</div>
          </div>
        </section>

        <section className="agendaList">
          <h3>Retornos e ligações</h3>
          {items.map((item) => (
            <div key={item.id} className={`agendaItem ${item.status}`}>
              <p className="agendaItemTitle">{item.title}</p>
              <p className="agendaItemDate">{item.date}</p>
            </div>
          ))}
        </section>
      </div>
    </div>
  );
}

export default App;
```

```css
/* App.css */
:root {
  --sidebar-bg: #2b0f4e;
  --sidebar-active: #7c3aed;
  --main-bg: #f7f7fb;
  --surface: #ffffff;
  --text-main: #1f2937;
  --text-soft: #6b7280;
  --border-soft: #e5e7eb;
  --alert: #ef476f;
  --success: #1f9d55;
  --warning: #d69e2e;
  --accent: #805ad5;
}

* {
  box-sizing: border-box;
}

body,
#root {
  margin: 0;
  font-family: Inter, system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
  color: var(--text-main);
  background: var(--main-bg);
}

.appShell {
  display: flex;
  min-height: 100vh;
}

/* Sidebar */
.sidebar {
  width: 260px;
  background: var(--sidebar-bg);
  color: #fff;
  padding: 16px 12px;
  display: flex;
  flex-direction: column;
  transition: width 0.25s ease;
  position: sticky;
  top: 0;
  height: 100vh;
}

.sidebar.collapsed {
  width: 78px;
}

.sidebarHeader {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 18px;
}

.logoPlaceholder {
  font-weight: 700;
  font-size: 0.95rem;
  white-space: nowrap;
  overflow: hidden;
}

.collapseBtn {
  background: rgba(255, 255, 255, 0.15);
  border: 0;
  color: #fff;
  border-radius: 8px;
  padding: 6px 8px;
  cursor: pointer;
}

.sidebarNav {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.navItem {
  background: transparent;
  color: #e9def8;
  border: 0;
  border-radius: 10px;
  padding: 10px 12px;
  display: flex;
  align-items: center;
  gap: 10px;
  text-align: left;
  cursor: pointer;
}

.navItem.active {
  background: var(--sidebar-active);
  color: #fff;
}

.navIcon {
  width: 20px;
  text-align: center;
}

.navText {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: 0.92rem;
}

.betaTag {
  font-size: 0.7rem;
  padding: 2px 6px;
  border-radius: 999px;
  background: #c4b5fd;
  color: #3b0764;
}

/* Main */
.mainArea {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
}

/* Topbar */
.topbar {
  background: var(--surface);
  border-bottom: 1px solid var(--border-soft);
  padding: 12px 18px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  position: sticky;
  top: 0;
  z-index: 4;
}

.newBtn {
  border: 1px solid var(--border-soft);
  background: #fff;
  border-radius: 10px;
  padding: 8px 14px;
  font-weight: 600;
  cursor: pointer;
}

.topbarActions {
  display: flex;
  align-items: center;
  gap: 10px;
}

.iconBtn {
  width: 36px;
  height: 36px;
  border: 1px solid var(--border-soft);
  border-radius: 10px;
  background: #fff;
  cursor: pointer;
  position: relative;
}

.withBadge .badge {
  position: absolute;
  top: -6px;
  right: -6px;
  background: #ef4444;
  color: #fff;
  font-size: 0.67rem;
  border-radius: 999px;
  padding: 2px 6px;
}

.userAvatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: #ddd6fe;
  color: #4c1d95;
  font-weight: 700;
  display: grid;
  place-items: center;
}

/* Filters */
.filterBar {
  display: flex;
  gap: 10px;
  padding: 10px 18px;
  background: #fafaff;
  border-bottom: 1px solid #f1f1f7;
  flex-wrap: wrap;
}

.filterSelect {
  border: 1px solid var(--border-soft);
  background: #fff;
  border-radius: 8px;
  padding: 8px 10px;
  color: #374151;
  min-width: 170px;
}

/* Kanban */
.kanbanArea {
  padding: 16px 18px 24px;
  flex: 1;
  overflow: auto;
}

.kanbanGrid {
  display: grid;
  grid-template-columns: repeat(4, minmax(250px, 1fr));
  gap: 14px;
}

.kanbanColumn {
  background: transparent;
  border-radius: 12px;
  padding: 8px;
  min-height: 300px;
  transition: background 0.2s ease, border 0.2s ease;
}

.kanbanColumn.isDropTarget {
  border: 2px dashed #c4b5fd;
  background: #f5f3ff;
}

.columnHeader h3 {
  margin: 0;
  font-size: 0.98rem;
}

.columnHeader p {
  margin: 4px 0 10px;
  color: var(--text-soft);
  font-size: 0.8rem;
}

.columnCards {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

/* Card */
.kanbanCard {
  background: #fff;
  border-radius: 12px;
  box-shadow: 0 1px 4px rgba(15, 23, 42, 0.08);
  padding: 12px;
  position: relative;
  transition: transform 0.15s ease, box-shadow 0.15s ease;
  border-left: 3px solid transparent;
}

.kanbanCard.hasAgendaAlert {
  border-left-color: #f43f5e;
}

.kanbanCard.isDragging {
  transform: scale(1.02);
  box-shadow: 0 14px 28px rgba(15, 23, 42, 0.18);
}

.editBtn {
  position: absolute;
  top: 8px;
  right: 8px;
  border: 0;
  background: #f3f4f6;
  border-radius: 8px;
  padding: 4px 6px;
  opacity: 0;
  transition: opacity 0.15s ease;
  cursor: pointer;
}

.kanbanCard:hover .editBtn {
  opacity: 1;
}

.cardTitle {
  margin: 2px 0 12px;
  font-weight: 600;
  font-size: 0.92rem;
}

.cardTitle span {
  color: #4b5563;
  font-weight: 500;
}

.cardFooter {
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: 8px;
}

.ownerAvatar {
  width: 26px;
  height: 26px;
  border-radius: 50%;
  background: #e5e7eb;
  font-size: 0.72rem;
  font-weight: 700;
  display: grid;
  place-items: center;
}

.moneyTag {
  font-size: 0.82rem;
  display: inline-flex;
  align-items: center;
  gap: 5px;
  color: #334155;
}

.moneyTag.green span {
  color: var(--success);
}
.moneyTag.yellow span {
  color: var(--warning);
}
.moneyTag.purple span {
  color: var(--accent);
}

.stageTime {
  background: #f3f4f6;
  color: #4b5563;
  padding: 4px 8px;
  border-radius: 999px;
  font-size: 0.74rem;
  white-space: nowrap;
}

.alertTime {
  color: #9f1239;
  font-weight: 600;
}
.alertTime.overdue {
  color: #b91c1c;
}

/* Agenda Modal */
.modalOverlay {
  position: fixed;
  inset: 0;
  background: rgba(15, 23, 42, 0.45);
  display: grid;
  place-items: center;
  z-index: 20;
  padding: 16px;
}

.agendaModal {
  width: min(760px, 100%);
  background: #fff;
  border-radius: 14px;
  box-shadow: 0 20px 60px rgba(15, 23, 42, 0.3);
  overflow: hidden;
}

.agendaHeader {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 16px;
  border-bottom: 1px solid var(--border-soft);
}

.agendaHeader h2 {
  margin: 0;
  font-size: 1.05rem;
}

.closeBtn {
  border: 0;
  background: #f3f4f6;
  border-radius: 8px;
  width: 32px;
  height: 32px;
  cursor: pointer;
}

.calendarView {
  padding: 14px 16px 10px;
}

.calendarGrid {
  display: grid;
  grid-template-columns: repeat(7, 1fr);
  gap: 8px;
}

.dayCell {
  border: 1px solid var(--border-soft);
  border-radius: 8px;
  padding: 10px 8px;
  text-align: center;
  font-size: 0.82rem;
}

.dayCell.today {
  background: #ede9fe;
  border-color: #a78bfa;
  color: #5b21b6;
  font-weight: 700;
}

.dayCell.muted {
  color: #9ca3af;
}

.agendaList {
  padding: 4px 16px 16px;
}

.agendaList h3 {
  margin: 8px 0 10px;
  font-size: 0.95rem;
}

.agendaItem {
  border: 1px solid var(--border-soft);
  border-radius: 10px;
  padding: 10px 12px;
  margin-bottom: 8px;
  background: #fff;
}

.agendaItem.today {
  border-left: 4px solid #7c3aed;
  background: #faf5ff;
}

.agendaItem.overdue {
  border-left: 4px solid #ef4444;
  background: #fff1f2;
}

.agendaItem.upcoming {
  border-left: 4px solid #22c55e;
}

.agendaItemTitle {
  margin: 0 0 4px;
  font-weight: 600;
  font-size: 0.9rem;
}

.agendaItemDate {
  margin: 0;
  font-size: 0.8rem;
  color: var(--text-soft);
}

/* Responsive */
@media (max-width: 1200px) {
  .kanbanGrid {
    grid-template-columns: repeat(2, minmax(250px, 1fr));
  }
}

@media (max-width: 860px) {
  .sidebar {
    width: 78px;
  }
  .sidebar .navText {
    display: none;
  }
  .logoPlaceholder {
    font-size: 0.85rem;
  }
  .kanbanGrid {
    grid-template-columns: 1fr;
  }
}
```

Se quiser, posso te entregar a mesma interface já quebrada em arquivos por componente (`components/Sidebar.jsx`, `components/KanbanCard.jsx`, etc.) para encaixar direto em um projeto React com organização mais limpa.
